    <rect x="20" y="204" width="660" height="44" rx="8" fill="#38bdf8" opacity="0.9"/>
    <text x="350" y="231" fill="#111113" font-size="14" font-weight="700" text-anchor="middle">2026年7月(現在): 21.26% — 4カ月で5倍以上急伸</text>

    <text x="20" y="285" fill="#a1a1aa" font-size="13">2. OP_RETURNデフォルト中継上限、コア vs ノッツ</text>
    <rect x="20" y="298" width="320" height="70" rx="8" fill="#3f3f46"/>
